"use client"

import { MarketGridUI } from "./market-grid-ui"
import {
  useMarketGrid,
  type MarketListing,
  type SortDirection,
  type SortField,
  type UseMarketGridOptions,
  type UseMarketGridReturn,
} from "./use-market-grid"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { ListingCardUI, type ListingCardUIProps } from "./listing-card-ui"
export { MarketGridUI, type MarketGridUIProps } from "./market-grid-ui"
export {
  useMarketGrid,
  type MarketListing,
  type OneSatTxo,
  type SortDirection,
  type SortField,
  type UseMarketGridOptions,
  type UseMarketGridReturn,
} from "./use-market-grid"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface MarketGridProps {
  /** Base URL of the 1sat-stack API */
  apiUrl?: string
  /** Number of listings per page */
  pageSize?: number
  /** Sort field */
  sortBy?: SortField
  /** Sort direction */
  sortDir?: SortDirection
  /** Optional content type filter (e.g. "image/png") */
  contentTypeFilter?: string
  /** Callback when "Buy" is clicked on a listing */
  onBuy: (outpoint: string, price: number) => void
  /** Callback when a listing card is clicked (navigation) */
  onListingClick?: (outpoint: string) => void
  /** Number of skeleton cards to show during loading */
  skeletonCount?: number
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * A responsive grid of ordinal NFT listings from the global orderbook.
 *
 * Fetches active OrdLock listings from the 1sat-stack API and renders each
 * as a card with ORDFS thumbnail, price badge, seller avatar, and buy action.
 * Supports pagination, loading skeletons, error recovery, and empty states.
 *
 * @example
 * ```tsx
 * import { MarketGrid } from "@/components/blocks/market-grid"
 *
 * <MarketGrid
 *   onBuy={(outpoint, price) => {
 *     console.log(`Buy ${outpoint} for ${price} sats`)
 *   }}
 *   onListingClick={(outpoint) => {
 *     router.push(`/ordinal/${outpoint}`)
 *   }}
 * />
 * ```
 */
export function MarketGrid({
  apiUrl,
  pageSize,
  sortBy,
  sortDir,
  contentTypeFilter,
  onBuy,
  onListingClick,
  skeletonCount,
  className,
}: MarketGridProps) {
  const grid = useMarketGrid({
    apiUrl,
    pageSize,
    sortBy,
    sortDir,
    contentTypeFilter,
  })

  return (
    <MarketGridUI
      listings={grid.listings}
      isLoading={grid.isLoading}
      isLoadingMore={grid.isLoadingMore}
      error={grid.error}
      hasMore={grid.hasMore}
      onLoadMore={grid.loadMore}
      onRefresh={grid.refresh}
      onBuy={onBuy}
      onListingClick={onListingClick}
      skeletonCount={skeletonCount}
      className={className}
    />
  )
}

"use client"

import { useState } from "react"
import { ShoppingCart } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardFooter,
} from "@/components/ui/card"
import { Skeleton } from "@/components/ui/skeleton"
import {
  Avatar,
  AvatarFallback,
} from "@/components/ui/avatar"
import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ListingCardUIProps {
  /** Outpoint of the listing (txid.vout) */
  outpoint: string
  /** Listing price in satoshis */
  price: number
  /** Seller address */
  seller: string
  /** Content type (MIME type) */
  contentType: string
  /** ORDFS thumbnail URL */
  thumbnailUrl: string
  /** Optional ordinal name */
  name: string | null
  /** Click on the "Buy" button */
  onBuy: (outpoint: string, price: number) => void
  /** Click on the card body to navigate */
  onListingClick?: (outpoint: string) => void
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function formatPrice(sats: number): string {
  if (sats >= 100000000) {
    return `${(sats / 100000000).toFixed(8)} BSV`
  }
  if (sats >= 1000000) {
    return `${(sats / 1000000).toFixed(2)}M sats`
  }
  if (sats >= 1000) {
    return `${(sats / 1000).toFixed(1)}K sats`
  }
  return `${sats.toLocaleString()} sats`
}

function truncateAddress(address: string, chars = 4): string {
  if (address.length <= chars * 2 + 3) return address
  return `${address.slice(0, chars)}...${address.slice(-chars)}`
}

function sellerInitials(address: string): string {
  if (address.length < 2) return "?"
  return address.slice(0, 2).toUpperCase()
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function ListingCardUI({
  outpoint,
  price,
  seller,
  contentType,
  thumbnailUrl,
  name,
  onBuy,
  onListingClick,
  className,
}: ListingCardUIProps) {
  const [imgLoaded, setImgLoaded] = useState(false)
  const [imgError, setImgError] = useState(false)

  const isImage = contentType.startsWith("image/")

  return (
    <Card
      className={cn(
        "group overflow-hidden transition-shadow hover:shadow-lg",
        onListingClick && "cursor-pointer",
        className,
      )}
      onClick={() => onListingClick?.(outpoint)}
      role={onListingClick ? "button" : undefined}
      tabIndex={onListingClick ? 0 : undefined}
      onKeyDown={(e) => {
        if (onListingClick && (e.key === "Enter" || e.key === " ")) {
          e.preventDefault()
          onListingClick(outpoint)
        }
      }}
    >
      {/* Thumbnail */}
      <div className="relative aspect-square overflow-hidden bg-muted">
        {isImage && !imgError ? (
          <>
            {!imgLoaded && (
              <Skeleton className="absolute inset-0 h-full w-full" />
            )}
            <img
              src={thumbnailUrl}
              alt={name ?? "Ordinal listing"}
              className={cn(
                "h-full w-full object-cover transition-transform duration-300 group-hover:scale-105",
                !imgLoaded && "opacity-0",
              )}
              onLoad={() => setImgLoaded(true)}
              onError={() => setImgError(true)}
            />
          </>
        ) : (
          <div className="flex h-full w-full items-center justify-center">
            <div className="text-center text-muted-foreground">
              <ShoppingCart className="mx-auto size-8 opacity-30" />
              <p className="mt-2 text-xs">
                {contentType || "Unknown type"}
              </p>
            </div>
          </div>
        )}

        {/* Price badge overlay */}
        <Badge
          variant="secondary"
          className="absolute bottom-2 right-2 bg-background/90 backdrop-blur-sm"
        >
          {formatPrice(price)}
        </Badge>
      </div>

      <CardContent className="flex flex-col gap-2 p-3 pb-2">
        {/* Name */}
        <h3 className="truncate text-sm font-semibold leading-none">
          {name ?? "Unnamed Ordinal"}
        </h3>

        {/* Seller row */}
        {seller && (
          <div className="flex items-center gap-2">
            <Avatar className="size-5">
              <AvatarFallback className="text-[8px]">
                {sellerInitials(seller)}
              </AvatarFallback>
            </Avatar>
            <span className="text-xs text-muted-foreground">
              {truncateAddress(seller)}
            </span>
          </div>
        )}
      </CardContent>

      <CardFooter className="p-3 pt-0">
        <Button
          className="w-full gap-2"
          size="sm"
          onClick={(e) => {
            e.stopPropagation()
            onBuy(outpoint, price)
          }}
          aria-label={`Buy ${name ?? "ordinal"} for ${formatPrice(price)}`}
        >
          <ShoppingCart data-icon="inline-start" />
          Buy
        </Button>
      </CardFooter>
    </Card>
  )
}

"use client"

import { AlertCircle, Loader2, RefreshCw, Store } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Skeleton } from "@/components/ui/skeleton"
import { Card, CardContent, CardFooter } from "@/components/ui/card"
import { cn } from "@/lib/utils"
import { ListingCardUI } from "./listing-card-ui"
import type { MarketListing } from "./use-market-grid"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface MarketGridUIProps {
  /** Listings to display */
  listings: MarketListing[]
  /** Whether the initial load is in progress */
  isLoading: boolean
  /** Whether more listings are loading */
  isLoadingMore: boolean
  /** Error message from the most recent fetch */
  error: string | null
  /** Whether there are more listings to load */
  hasMore: boolean
  /** Load next page */
  onLoadMore: () => void
  /** Re-fetch listings from the beginning */
  onRefresh: () => void
  /** Callback when "Buy" is clicked on a listing */
  onBuy: (outpoint: string, price: number) => void
  /** Callback when a listing card is clicked (navigation) */
  onListingClick?: (outpoint: string) => void
  /** Number of skeleton cards to show during loading */
  skeletonCount?: number
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const ORDFS_CONTENT_URL = "https://ordfs.network/content"

// ---------------------------------------------------------------------------
// Skeleton grid
// ---------------------------------------------------------------------------

function SkeletonCard() {
  return (
    <Card className="overflow-hidden">
      <Skeleton className="aspect-square w-full" />
      <CardContent className="flex flex-col gap-2 p-3 pb-2">
        <Skeleton className="h-4 w-3/4" />
        <div className="flex items-center gap-2">
          <Skeleton className="size-5 rounded-full" />
          <Skeleton className="h-3 w-20" />
        </div>
      </CardContent>
      <CardFooter className="p-3 pt-0">
        <Skeleton className="h-8 w-full" />
      </CardFooter>
    </Card>
  )
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function MarketGridUI({
  listings,
  isLoading,
  isLoadingMore,
  error,
  hasMore,
  onLoadMore,
  onRefresh,
  onBuy,
  onListingClick,
  skeletonCount = 8,
  className,
}: MarketGridUIProps) {
  // Loading state: grid of skeletons
  if (isLoading) {
    return (
      <div className={cn("flex flex-col gap-6", className)}>
        <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 lg:grid-cols-4">
          {Array.from({ length: skeletonCount }, (_, i) => (
            <SkeletonCard key={i} />
          ))}
        </div>
      </div>
    )
  }

  // Error state (no listings loaded)
  if (error && listings.length === 0) {
    return (
      <div className={cn("flex flex-col gap-6", className)}>
        <div className="flex flex-col items-center justify-center gap-4 rounded-lg border border-dashed p-10">
          <AlertCircle className="size-10 text-destructive" />
          <div className="flex flex-col gap-1 text-center">
            <p className="text-sm font-medium">Failed to load listings</p>
            <p className="text-xs text-muted-foreground">{error}</p>
          </div>
          <Button variant="outline" size="sm" onClick={onRefresh} className="gap-2">
            <RefreshCw data-icon="inline-start" />
            Retry
          </Button>
        </div>
      </div>
    )
  }

  // Empty state
  if (listings.length === 0) {
    return (
      <div className={cn("flex flex-col gap-6", className)}>
        <div className="flex flex-col items-center justify-center gap-4 rounded-lg border border-dashed p-10">
          <div className="mx-auto flex size-12 items-center justify-center rounded-full bg-muted">
            <Store className="size-6 text-muted-foreground" />
          </div>
          <div className="flex flex-col gap-1 text-center">
            <p className="text-sm font-medium">No listings found</p>
            <p className="text-xs text-muted-foreground">
              There are no ordinals listed for sale right now. Check back later.
            </p>
          </div>
          <Button variant="outline" size="sm" onClick={onRefresh} className="gap-2">
            <RefreshCw data-icon="inline-start" />
            Refresh
          </Button>
        </div>
      </div>
    )
  }

  // Grid with listings
  return (
    <div className={cn("flex flex-col gap-6", className)}>
      <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 lg:grid-cols-4">
        {listings.map((listing) => (
          <ListingCardUI
            key={listing.outpoint}
            outpoint={listing.outpoint}
            price={listing.price}
            seller={listing.seller}
            contentType={listing.contentType}
            thumbnailUrl={`${ORDFS_CONTENT_URL}/${listing.origin}`}
            name={listing.name}
            onBuy={onBuy}
            onListingClick={onListingClick}
          />
        ))}
      </div>

      {/* Inline error after partial load */}
      {error && listings.length > 0 && (
        <div className="flex items-center justify-center gap-2 text-sm text-destructive">
          <AlertCircle className="size-4" />
          <span>{error}</span>
        </div>
      )}

      {/* Load more */}
      {hasMore && (
        <div className="flex justify-center">
          <Button
            variant="outline"
            onClick={onLoadMore}
            disabled={isLoadingMore}
            className="gap-2"
          >
            {isLoadingMore ? (
              <>
                <Loader2 className="animate-spin" data-icon="inline-start" />
                Loading...
              </>
            ) : (
              "Load More"
            )}
          </Button>
        </div>
      )}
    </div>
  )
}

import { useCallback, useEffect, useRef, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Raw TXO record from the 1sat-stack API */
export interface OneSatTxo {
  /** Transaction ID */
  txid: string
  /** Output index */
  vout: number
  /** Outpoint in "txid.vout" format */
  outpoint: string
  /** Satoshi value of the output */
  satoshis: number
  /** Locking script hex */
  script: string
  /** Content type from inscription */
  type?: string
  /** Origin outpoint for the inscription */
  origin?: string
  /** MAP metadata */
  MAP?: Record<string, string>
  /** Listing price from ordlock decode (sats) */
  price?: number
  /** Seller address decoded from ordlock */
  seller?: string
  /** BMAP metadata name */
  name?: string
}

/** Normalized listing for display */
export interface MarketListing {
  /** Outpoint of the listing (txid.vout) */
  outpoint: string
  /** Listing price in satoshis */
  price: number
  /** Seller address (base58check) */
  seller: string
  /** Content type (MIME type) */
  contentType: string
  /** Origin outpoint for ORDFS thumbnail */
  origin: string
  /** Optional name from MAP metadata */
  name: string | null
}

export type SortField = "price" | "recent"
export type SortDirection = "asc" | "desc"

export interface UseMarketGridOptions {
  /** Base URL of the 1sat-stack API */
  apiUrl?: string
  /** Number of listings per page */
  pageSize?: number
  /** Sort field */
  sortBy?: SortField
  /** Sort direction */
  sortDir?: SortDirection
  /** Optional content type filter (e.g. "image/png") */
  contentTypeFilter?: string
}

export interface UseMarketGridReturn {
  /** Currently loaded listings */
  listings: MarketListing[]
  /** Whether the initial load is in progress */
  isLoading: boolean
  /** Whether a subsequent page is loading */
  isLoadingMore: boolean
  /** Error from the most recent fetch */
  error: string | null
  /** Whether there are more pages to load */
  hasMore: boolean
  /** Load the next page */
  loadMore: () => void
  /** Re-fetch from the beginning */
  refresh: () => void
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const DEFAULT_API_URL = "https://api.1sat.app"
const DEFAULT_PAGE_SIZE = 20

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function normalizeTxo(txo: OneSatTxo): MarketListing | null {
  const price = txo.price ?? 0
  if (price <= 0) return null

  return {
    outpoint: txo.outpoint ?? `${txo.txid}.${txo.vout}`,
    price,
    seller: txo.seller ?? "",
    contentType: txo.type ?? "application/octet-stream",
    origin: txo.origin ?? txo.outpoint ?? `${txo.txid}.${txo.vout}`,
    name: txo.name ?? txo.MAP?.name ?? null,
  }
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useMarketGrid({
  apiUrl = DEFAULT_API_URL,
  pageSize = DEFAULT_PAGE_SIZE,
  sortBy = "recent",
  sortDir = "desc",
  contentTypeFilter,
}: UseMarketGridOptions = {}): UseMarketGridReturn {
  const [listings, setListings] = useState<MarketListing[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [isLoadingMore, setIsLoadingMore] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [hasMore, setHasMore] = useState(true)
  const offsetRef = useRef(0)
  const abortRef = useRef<AbortController | null>(null)

  const fetchPage = useCallback(
    async (offset: number, signal: AbortSignal): Promise<MarketListing[]> => {
      const params = new URLSearchParams({
        tags: "ordlock",
        unspent: "true",
        limit: String(pageSize),
        offset: String(offset),
      })

      if (contentTypeFilter) {
        params.set("type", contentTypeFilter)
      }

      if (sortBy === "price") {
        params.set("sort", "price")
        params.set("dir", sortDir)
      }

      const url = `${apiUrl}/1sat/txo/search?${params.toString()}`

      const response = await fetch(url, { signal })

      if (!response.ok) {
        throw new Error(`API returned ${response.status}: ${response.statusText}`)
      }

      const data: OneSatTxo[] = await response.json()

      const normalized: MarketListing[] = []
      for (const txo of data) {
        const listing = normalizeTxo(txo)
        if (listing) normalized.push(listing)
      }

      return normalized
    },
    [apiUrl, pageSize, sortBy, sortDir, contentTypeFilter],
  )

  const loadInitial = useCallback(async () => {
    abortRef.current?.abort()
    const controller = new AbortController()
    abortRef.current = controller

    setIsLoading(true)
    setError(null)
    setListings([])
    offsetRef.current = 0

    try {
      const page = await fetchPage(0, controller.signal)
      setListings(page)
      offsetRef.current = page.length
      setHasMore(page.length >= pageSize)
    } catch (err) {
      if (err instanceof DOMException && err.name === "AbortError") return
      const msg = err instanceof Error ? err.message : "Failed to load listings"
      setError(msg)
    } finally {
      setIsLoading(false)
    }
  }, [fetchPage, pageSize])

  const loadMore = useCallback(async () => {
    if (isLoadingMore || !hasMore) return

    abortRef.current?.abort()
    const controller = new AbortController()
    abortRef.current = controller

    setIsLoadingMore(true)
    setError(null)

    try {
      const page = await fetchPage(offsetRef.current, controller.signal)
      setListings((prev) => [...prev, ...page])
      offsetRef.current += page.length
      setHasMore(page.length >= pageSize)
    } catch (err) {
      if (err instanceof DOMException && err.name === "AbortError") return
      const msg = err instanceof Error ? err.message : "Failed to load more listings"
      setError(msg)
    } finally {
      setIsLoadingMore(false)
    }
  }, [fetchPage, pageSize, isLoadingMore, hasMore])

  // Load on mount and when fetch params change
  useEffect(() => {
    loadInitial()

    return () => {
      abortRef.current?.abort()
    }
  }, [loadInitial])

  return {
    listings,
    isLoading,
    isLoadingMore,
    error,
    hasMore,
    loadMore,
    refresh: loadInitial,
  }
}
